 1	import React from 'react';
 2	
 3	import Loading from '@kubevirt-utils/components/Loading/Loading';
 4	import { updateVMCustomizeIT, vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 5	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 6	import SchedulingSection from '@virtualmachines/details/tabs/configuration/scheduling/components/SchedulingSection';
 7	
 8	const CustomizeInstanceTypeSchedulingTab = () => {
 9	  const vm = vmSignal.value;
10	
11	  if (!vm) {
12	    return <Loading />;
13	  }
14	
15	  return (
16	    <PageSection variant={PageSectionVariants.light}>
17	      <SchedulingSection onSubmit={updateVMCustomizeIT} vm={vm} />
18	    </PageSection>
19	  );
20	};
21	
22	export default CustomizeInstanceTypeSchedulingTab;

